"use strict";parserFactory.register("shikkakutranslations.org",()=>new ShikkakutranslationsParser);class ShikkakutranslationsImageCollector extends ImageCollector{constructor(){super()}isImageWrapperElement(e){return"div"===e.tagName.toLowerCase()&&e.className.startsWith("gallery-group")||super.isImageWrapperElement(e)}}class ShikkakutranslationsParser extends Parser{constructor(){super(new ShikkakutranslationsImageCollector)}getChapterUrls(e){let r=e.querySelector("div.menu-header");return Promise.resolve(util.hyperlinksToChapterList(r))}findContent(e){return e.querySelector("div#content-body div.entry")}findChapterTitle(e){return e.querySelector("h1.page-title")}removeNextAndPreviousChapterHyperlinks(e,r){[...r.querySelectorAll("a")].filter(e=>null===e.querySelector("img")).map(e=>this.findParentNodeOfChapterLinkToRemoveAt(e)).forEach(e=>e.remove())}findParentNodeOfChapterLinkToRemoveAt(e){return util.moveIfParent(e,"p")}}